import{_ as i,o as a,c as e,ag as n}from"./chunks/framework.CTpQozEL.js";const c=JSON.parse('{"title":"Telegram","description":"Telegram 봇 지원 상태, 기능 및 구성","frontmatter":{"title":"Telegram","description":"Telegram 봇 지원 상태, 기능 및 구성"},"headers":[],"relativePath":"channels/telegram.md","filePath":"channels/telegram.md","lastUpdated":null}'),l={name:"channels/telegram.md"};function t(p,s,h,o,k,r){return a(),e("div",null,[...s[0]||(s[0]=[n('<p>grammY를 통한 봇 DM 및 그룹에서 프로덕션 준비 완료입니다. 기본 모드는 long polling이며, webhook 모드는 선택 사항입니다.</p><blockquote><p><strong>페어링</strong> Telegram의 기본 DM 정책은 페어링입니다.</p></blockquote><blockquote><p><strong>채널 문제 해결</strong> 채널 간 진단 및 복구 플레이북입니다.</p></blockquote><blockquote><p><strong>게이트웨이 구성</strong> 전체 채널 구성 패턴과 예시입니다.</p></blockquote><h2 id="빠른-설정" tabindex="-1">빠른 설정 <a class="header-anchor" href="#빠른-설정" aria-label="Permalink to &quot;빠른 설정&quot;">​</a></h2><ol><li><p><strong>BotFather에서 봇 토큰 생성</strong></p><p>Telegram을 열고 <strong>@BotFather</strong>와 대화를 시작합니다 (핸들이 정확히 <code>@BotFather</code>인지 확인).</p><pre><code>`/newbot`을 실행하고 프롬프트에 따라 진행한 후 토큰을 저장합니다.\n</code></pre></li><li><p><strong>토큰 및 DM 정책 구성</strong></p></li></ol><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      botToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123:abc&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>   환경 변수 폴백: `TELEGRAM_BOT_TOKEN=...` (기본 계정에만 적용).\n   Telegram은 `openclaw channels login telegram`을 사용하지 **않습니다**. 구성/환경 변수에서 토큰을 설정한 후 게이트웨이를 시작하세요.\n</code></pre><ol start="3"><li><strong>게이트웨이 시작 및 첫 DM 승인</strong></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><pre><code>   페어링 코드는 1시간 후 만료됩니다.\n</code></pre><ol start="4"><li><strong>그룹에 봇 추가</strong></li></ol><p>봇을 그룹에 추가한 후, 접근 모델에 맞게 <code>channels.telegram.groups</code>와 <code>groupPolicy</code>를 설정합니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>토큰 해석 순서는 계정 인식 방식입니다. 실제로는 구성 값이 환경 변수 폴백보다 우선하며, <code>TELEGRAM_BOT_TOKEN</code>은 기본 계정에만 적용됩니다.</p></div><h2 id="telegram-측-설정" tabindex="-1">Telegram 측 설정 <a class="header-anchor" href="#telegram-측-설정" aria-label="Permalink to &quot;Telegram 측 설정&quot;">​</a></h2><details class="details custom-block"><summary>Privacy mode와 그룹 가시성</summary><p>Telegram 봇은 기본적으로 <strong>Privacy Mode</strong>가 활성화되어 있어, 봇이 받을 수 있는 그룹 메시지를 제한합니다.</p><pre><code>봇이 모든 그룹 메시지를 볼 수 있어야 한다면, 다음 중 하나를 수행하세요:\n\n- `/setprivacy`를 통해 privacy mode를 비활성화하거나,\n- 봇을 그룹 관리자(admin)로 만듭니다.\n\nprivacy mode를 토글할 때는, Telegram이 변경 사항을 적용하도록 각 그룹에서 봇을 제거 후 다시 추가하세요.\n</code></pre></details><details class="details custom-block"><summary>그룹 권한</summary><p>관리자 상태는 Telegram 그룹 설정에서 제어됩니다.</p><pre><code>관리자 봇은 모든 그룹 메시지를 수신하므로, 항상 켜져 있는(always-on) 그룹 동작에 유용합니다.\n</code></pre></details><details class="details custom-block"><summary>유용한 BotFather 토글</summary><ul><li><code>/setjoingroups</code> — 그룹 추가 허용/거부 <ul><li><code>/setprivacy</code> — 그룹 가시성 동작 설정</li></ul></li></ul></details><h2 id="접근-제어-및-활성화" tabindex="-1">접근 제어 및 활성화 <a class="header-anchor" href="#접근-제어-및-활성화" aria-label="Permalink to &quot;접근 제어 및 활성화&quot;">​</a></h2><p><strong>DM 정책</strong></p><p><code>channels.telegram.dmPolicy</code>는 다이렉트 메시지 접근을 제어합니다:</p><pre><code>- `pairing` (기본값)\n- `allowlist` (`allowFrom`에 최소 한 개의 발신자 ID 필요)\n- `open` (`allowFrom`에 `&quot;*&quot;` 포함 필요)\n- `disabled`\n\n`channels.telegram.allowFrom`은 숫자형 Telegram 사용자 ID를 허용합니다. `telegram:` / `tg:` 접두사는 허용되며 정규화됩니다.\n`allowFrom`이 비어 있는 `dmPolicy: &quot;allowlist&quot;`는 모든 DM을 차단하며, 구성 검증에서 거부됩니다.\n설정은 숫자형 사용자 ID만 요청합니다.\n업그레이드 후 구성에 `@username` allowlist 항목이 있다면, `openclaw doctor --fix`를 실행하여 해결하세요 (best-effort이며, Telegram 봇 토큰이 필요합니다).\n이전에 pairing-store allowlist 파일에 의존했다면, `openclaw doctor --fix`가 allowlist 흐름에서 항목을 `channels.telegram.allowFrom`으로 복구할 수 있습니다 (예: `dmPolicy: &quot;allowlist&quot;`에 아직 명시적 ID가 없는 경우).\n\n단일 소유자 봇의 경우, 접근 정책을 구성에 영구적으로 유지하려면 명시적 숫자 `allowFrom` ID와 함께 `dmPolicy: &quot;allowlist&quot;`를 선호하세요 (이전 페어링 승인에 의존하는 대신).\n\n흔한 혼동: DM 페어링 승인은 &quot;이 발신자가 어디서든 인증됨&quot;을 의미하지 않습니다.\n페어링은 DM 접근만 부여합니다. 그룹 발신자 인증은 여전히 명시적인 구성 allowlist에서 가져옵니다.\n&quot;한 번 인증되면 DM과 그룹 명령이 모두 동작&quot;하길 원한다면, 숫자형 Telegram 사용자 ID를 `channels.telegram.allowFrom`에 넣으세요.\n\n### Telegram 사용자 ID 찾기\n\n더 안전한 방법 (서드파티 봇 없음):\n\n1. 봇에게 DM을 보냅니다.\n2. `openclaw logs --follow`를 실행합니다.\n3. `from.id`를 읽습니다.\n\n공식 Bot API 방법:\n</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api.telegram.org/bot&lt;bot_token&gt;/getUpdates&quot;</span></span></code></pre></div><pre><code>서드파티 방법 (프라이버시가 덜함): `@userinfobot` 또는 `@getidsbot`.\n</code></pre><p><strong>그룹 정책 및 allowlist</strong></p><p>두 가지 제어가 함께 적용됩니다:</p><pre><code>1. **허용되는 그룹** (`channels.telegram.groups`)\n   - `groups` 구성이 없을 때:\n     - `groupPolicy: &quot;open&quot;`의 경우: 모든 그룹이 그룹 ID 체크를 통과할 수 있음\n     - `groupPolicy: &quot;allowlist&quot;`(기본값)의 경우: `groups` 항목 (또는 `&quot;*&quot;`)을 추가할 때까지 그룹이 차단됨\n   - `groups`가 구성됨: allowlist로 작동 (명시적 ID 또는 `&quot;*&quot;`)\n\n2. **그룹에서 허용되는 발신자** (`channels.telegram.groupPolicy`)\n   - `open`\n   - `allowlist` (기본값)\n   - `disabled`\n\n`groupAllowFrom`은 그룹 발신자 필터링에 사용됩니다. 설정되지 않으면, Telegram은 `allowFrom`으로 폴백합니다.\n`groupAllowFrom` 항목은 숫자형 Telegram 사용자 ID여야 합니다 (`telegram:` / `tg:` 접두사는 정규화됨).\nTelegram 그룹 또는 슈퍼그룹 채팅 ID를 `groupAllowFrom`에 넣지 마세요. 음수 채팅 ID는 `channels.telegram.groups` 아래에 속합니다.\n숫자가 아닌 항목은 발신자 인증에 무시됩니다.\n보안 경계 (`2026.2.25+`): 그룹 발신자 인증은 DM pairing-store 승인을 **상속하지 않습니다**.\n페어링은 DM 전용으로 유지됩니다. 그룹의 경우 `groupAllowFrom` 또는 그룹별/주제(topic)별 `allowFrom`을 설정하세요.\n`groupAllowFrom`이 설정되지 않으면, Telegram은 pairing store가 아니라 구성의 `allowFrom`으로 폴백합니다.\n단일 소유자 봇을 위한 실용적 패턴: 사용자 ID를 `channels.telegram.allowFrom`에 설정하고, `groupAllowFrom`은 설정하지 않으며, 대상 그룹을 `channels.telegram.groups` 아래에 허용하는 것입니다.\n런타임 참고: `channels.telegram`이 완전히 누락된 경우, 런타임은 `channels.defaults.groupPolicy`가 명시적으로 설정되지 않는 한 fail-closed `groupPolicy=&quot;allowlist&quot;`를 기본값으로 사용합니다.\n\n예시: 특정 그룹 하나의 모든 멤버 허용:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;-1001234567890&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          groupPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;open&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>예시: 특정 그룹 내 특정 사용자만 허용:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;-1001234567890&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8734062810&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;745123456&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>::: warning\n</code></pre><p>흔한 실수: <code>groupAllowFrom</code>은 Telegram 그룹 allowlist가 <strong>아닙니다</strong>.</p><pre><code>  - `-1001234567890` 같은 음수 Telegram 그룹 또는 슈퍼그룹 채팅 ID는 `channels.telegram.groups` 아래에 넣습니다.\n  - `8734062810` 같은 Telegram 사용자 ID는 허용된 그룹 내에서 봇을 트리거할 수 있는 사람을 제한하려는 경우 `groupAllowFrom`에 넣습니다.\n  - 허용된 그룹의 모든 멤버가 봇과 대화할 수 있게 하려는 경우에만 `groupAllowFrom: [&quot;*&quot;]`을 사용합니다.\n</code></pre><p>:::</p><p><strong>멘션(mention) 동작</strong></p><p>그룹 응답은 기본적으로 멘션을 필요로 합니다.</p><pre><code>멘션은 다음에서 올 수 있습니다:\n\n- 네이티브 `@botusername` 멘션, 또는\n- 다음의 멘션 패턴:\n  - `agents.list[].groupChat.mentionPatterns`\n  - `messages.groupChat.mentionPatterns`\n\n세션 수준 명령 토글:\n\n- `/activation always`\n- `/activation mention`\n\n이는 세션 상태만 업데이트합니다. 영구 설정에는 config를 사용하세요.\n\n영구 구성 예시:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>그룹 채팅 ID 얻기:\n\n- 그룹 메시지를 `@userinfobot` / `@getidsbot`으로 전달\n- 또는 `openclaw logs --follow`에서 `chat.id`를 읽기\n- 또는 Bot API `getUpdates` 검사\n</code></pre><h2 id="런타임-동작" tabindex="-1">런타임 동작 <a class="header-anchor" href="#런타임-동작" aria-label="Permalink to &quot;런타임 동작&quot;">​</a></h2><ul><li>Telegram은 게이트웨이 프로세스가 소유합니다.</li><li>라우팅은 결정적입니다: Telegram 인바운드는 Telegram으로 응답합니다 (모델이 채널을 선택하지 않음).</li><li>인바운드 메시지는 공유 채널 envelope로 정규화되며 reply 메타데이터와 미디어 placeholder를 포함합니다.</li><li>그룹 세션은 group ID로 격리됩니다. 포럼 토픽은 <code>:topic:&lt;threadId&gt;</code>를 추가하여 토픽을 격리합니다.</li><li>DM 메시지는 <code>message_thread_id</code>를 전달할 수 있으며, OpenClaw는 thread-aware 세션 키로 라우팅하고 응답을 위해 thread ID를 보존합니다.</li><li>Long polling은 per-chat/per-thread 시퀀싱과 함께 grammY runner를 사용합니다. 전체 runner sink 동시성은 <code>agents.defaults.maxConcurrent</code>를 사용합니다.</li><li>Long-polling watchdog 재시작은 기본적으로 <code>getUpdates</code> liveness 완료 없이 120초 후에 트리거됩니다. 배포 환경에서 장시간 작업 중 여전히 false polling-stall 재시작이 발생하는 경우에만 <code>channels.telegram.pollingStallThresholdMs</code>를 늘리세요. 값은 밀리초이며 <code>30000</code>부터 <code>600000</code>까지 허용되고, 계정별 override가 지원됩니다.</li><li>Telegram Bot API는 읽음 영수증(read-receipt) 지원이 없습니다 (<code>sendReadReceipts</code>는 적용되지 않음).</li></ul><h2 id="기능-참조" tabindex="-1">기능 참조 <a class="header-anchor" href="#기능-참조" aria-label="Permalink to &quot;기능 참조&quot;">​</a></h2><details class="details custom-block"><summary>라이브 스트림 프리뷰 (메시지 편집)</summary><p>OpenClaw는 부분 응답을 실시간으로 스트리밍할 수 있습니다:</p><pre><code>- 다이렉트 채팅: 프리뷰 메시지 + `editMessageText`\n- 그룹/토픽: 프리뷰 메시지 + `editMessageText`\n\n요구 사항:\n\n- `channels.telegram.streaming`은 `off | partial | block | progress` (기본값: `partial`)\n- `progress`는 Telegram에서 `partial`로 매핑됩니다 (채널 간 명명 호환성)\n- `streaming.preview.toolProgress`는 도구/진행 상황 업데이트가 동일한 편집된 프리뷰 메시지를 재사용할지 여부를 제어합니다 (기본값: `true`). 별도의 도구/진행 메시지를 유지하려면 `false`로 설정하세요.\n- 레거시 `channels.telegram.streamMode` 및 boolean `streaming` 값은 자동 매핑됩니다.\n\n텍스트 전용 응답의 경우:\n\n- DM: OpenClaw는 동일한 프리뷰 메시지를 유지하고 제자리에서 최종 편집을 수행합니다 (두 번째 메시지 없음)\n- 그룹/토픽: OpenClaw는 동일한 프리뷰 메시지를 유지하고 제자리에서 최종 편집을 수행합니다 (두 번째 메시지 없음)\n\n복잡한 응답 (예: 미디어 페이로드)의 경우, OpenClaw는 일반 최종 전달로 폴백한 후 프리뷰 메시지를 정리합니다.\n\n프리뷰 스트리밍은 block 스트리밍과 별개입니다. Telegram에 대해 block 스트리밍이 명시적으로 활성화되면, OpenClaw는 double-streaming을 피하기 위해 프리뷰 스트림을 건너뜁니다.\n\n네이티브 draft 전송이 사용 불가능/거부되는 경우, OpenClaw는 자동으로 `sendMessage` + `editMessageText`로 폴백합니다.\n\nTelegram 전용 reasoning 스트림:\n\n- `/reasoning stream`은 생성 중에 reasoning을 라이브 프리뷰로 전송합니다\n- 최종 답변은 reasoning 텍스트 없이 전송됩니다\n</code></pre></details><details class="details custom-block"><summary>포맷팅 및 HTML 폴백</summary><p>아웃바운드 텍스트는 Telegram <code>parse_mode: &quot;HTML&quot;</code>을 사용합니다.</p><pre><code>- Markdown 스타일 텍스트는 Telegram-safe HTML로 렌더링됩니다.\n- 원시 모델 HTML은 Telegram 파싱 실패를 줄이기 위해 escape 처리됩니다.\n- Telegram이 파싱된 HTML을 거부하면, OpenClaw는 일반 텍스트로 재시도합니다.\n\n링크 프리뷰는 기본적으로 활성화되며, `channels.telegram.linkPreview: false`로 비활성화할 수 있습니다.\n</code></pre></details><details class="details custom-block"><summary>네이티브 명령과 커스텀 명령</summary><p>Telegram 명령 메뉴 등록은 시작 시 <code>setMyCommands</code>로 처리됩니다.</p><pre><code>네이티브 명령 기본값:\n\n- `commands.native: &quot;auto&quot;`는 Telegram에 대해 네이티브 명령을 활성화합니다.\n\n커스텀 명령 메뉴 항목 추가:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      customCommands</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;backup&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Git backup&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;generate&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Create an image&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>규칙:\n\n- 이름은 정규화됩니다 (선행 `/` 제거, 소문자)\n- 유효한 패턴: `a-z`, `0-9`, `_`, 길이 `1..32`\n- 커스텀 명령은 네이티브 명령을 덮어쓸 수 없습니다\n- 충돌/중복은 건너뛰고 기록됩니다\n\n참고:\n\n- 커스텀 명령은 메뉴 항목일 뿐이며, 동작을 자동 구현하지 않습니다\n- Telegram 메뉴에 표시되지 않더라도, 입력되면 플러그인/스킬 명령은 여전히 작동할 수 있습니다\n\n네이티브 명령이 비활성화되면, 내장(built-in) 명령은 제거됩니다. 커스텀/플러그인 명령은 구성된 경우 여전히 등록될 수 있습니다.\n\n일반적인 설정 실패:\n\n- `setMyCommands failed`와 `BOT_COMMANDS_TOO_MUCH`는 Telegram 메뉴가 트리밍 후에도 여전히 오버플로되었음을 의미합니다. 플러그인/스킬/커스텀 명령을 줄이거나 `channels.telegram.commands.native`를 비활성화하세요.\n- `setMyCommands failed`와 네트워크/fetch 오류는 보통 `api.telegram.org`로의 아웃바운드 DNS/HTTPS가 차단되었음을 의미합니다.\n\n### 기기 페어링 명령 (`device-pair` 플러그인)\n\n`device-pair` 플러그인이 설치된 경우:\n\n1. `/pair`가 설정 코드를 생성합니다\n2. iOS 앱에 코드를 붙여넣습니다\n3. `/pair pending`이 대기 중인 요청을 나열합니다 (role/scopes 포함)\n4. 요청을 승인합니다:\n   - 명시적 승인: `/pair approve &lt;requestId&gt;`\n   - 대기 중 요청이 하나만 있는 경우: `/pair approve`\n   - 최신 요청: `/pair approve latest`\n\n설정 코드는 수명이 짧은 bootstrap 토큰을 전달합니다. 내장 bootstrap handoff는 주 노드 토큰을 `scopes: []`로 유지합니다. handoff된 operator 토큰은 `operator.approvals`, `operator.read`, `operator.talk.secrets`, `operator.write`로 제한됩니다. Bootstrap scope 체크는 role-prefixed이므로, operator allowlist는 operator 요청만 충족하고, non-operator role은 자신의 role 접두사 아래 scope가 여전히 필요합니다.\n\n기기가 변경된 인증 세부 정보(예: role/scopes/공개 키)로 재시도하면, 이전 대기 요청은 대체되고 새 요청은 다른 `requestId`를 사용합니다. 승인 전에 `/pair pending`을 다시 실행하세요.\n\n자세한 내용: [페어링](/channels/pairing#pair-via-telegram-recommended-for-ios).\n</code></pre></details><details class="details custom-block"><summary>인라인 버튼</summary><p>인라인 키보드 scope 구성:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        inlineButtons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>계정별 override:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accounts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            inlineButtons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>Scope:\n\n- `off`\n- `dm`\n- `group`\n- `all`\n- `allowlist` (기본값)\n\n레거시 `capabilities: [&quot;inlineButtons&quot;]`는 `inlineButtons: &quot;all&quot;`로 매핑됩니다.\n\n메시지 액션 예시:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;send&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Choose an option:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  buttons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Yes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">callback_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;yes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;No&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">callback_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;no&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [{ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Cancel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">callback_data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cancel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>콜백 클릭은 에이전트에 텍스트로 전달됩니다:\n`callback_data: &lt;value&gt;`\n</code></pre></details><details class="details custom-block"><summary>에이전트 및 자동화를 위한 Telegram 메시지 액션</summary><p>Telegram 도구 액션에는 다음이 포함됩니다:</p><pre><code>- `sendMessage` (`to`, `content`, 선택적 `mediaUrl`, `replyToMessageId`, `messageThreadId`)\n- `react` (`chatId`, `messageId`, `emoji`)\n- `deleteMessage` (`chatId`, `messageId`)\n- `editMessage` (`chatId`, `messageId`, `content`)\n- `createForumTopic` (`chatId`, `name`, 선택적 `iconColor`, `iconCustomEmojiId`)\n\n채널 메시지 액션은 사용하기 편리한 별칭(`send`, `react`, `delete`, `edit`, `sticker`, `sticker-search`, `topic-create`)을 노출합니다.\n\n게이팅 제어:\n\n- `channels.telegram.actions.sendMessage`\n- `channels.telegram.actions.deleteMessage`\n- `channels.telegram.actions.reactions`\n- `channels.telegram.actions.sticker` (기본값: 비활성화)\n\n참고: `edit`와 `topic-create`는 현재 기본적으로 활성화되어 있으며 별도의 `channels.telegram.actions.*` 토글이 없습니다.\n런타임 전송은 활성 config/secrets 스냅샷(시작/재로드)을 사용하므로, 액션 경로는 전송당 즉석 SecretRef 재해석을 수행하지 않습니다.\n\nReaction 제거 시맨틱: [/tools/reactions](/tools/reactions)\n</code></pre></details><details class="details custom-block"><summary>Reply threading 태그</summary><p>Telegram은 생성된 출력에서 명시적 reply threading 태그를 지원합니다:</p><pre><code>- `[[reply_to_current]]`는 트리거 메시지에 답장합니다\n- `[[reply_to:&lt;id&gt;]]`는 특정 Telegram 메시지 ID에 답장합니다\n\n`channels.telegram.replyToMode`는 처리를 제어합니다:\n\n- `off` (기본값)\n- `first`\n- `all`\n\n참고: `off`는 암시적 reply threading을 비활성화합니다. 명시적 `[[reply_to_*]]` 태그는 여전히 존중됩니다.\n</code></pre></details><details class="details custom-block"><summary>포럼 토픽 및 스레드 동작</summary><p>포럼 슈퍼그룹:</p><pre><code>- 토픽 세션 키는 `:topic:&lt;threadId&gt;`를 추가합니다\n- 답장과 타이핑은 토픽 스레드를 대상으로 합니다\n- 토픽 구성 경로:\n  `channels.telegram.groups.&lt;chatId&gt;.topics.&lt;threadId&gt;`\n\nGeneral topic (`threadId=1`) 특수 케이스:\n\n- 메시지 전송은 `message_thread_id`를 생략합니다 (Telegram이 `sendMessage(...thread_id=1)`을 거부함)\n- 타이핑 액션은 여전히 `message_thread_id`를 포함합니다\n\n토픽 상속: 토픽 항목은 override되지 않는 한 그룹 설정을 상속합니다 (`requireMention`, `allowFrom`, `skills`, `systemPrompt`, `enabled`, `groupPolicy`).\n`agentId`는 토픽 전용이며 그룹 기본값에서 상속되지 않습니다.\n\n**토픽별 에이전트 라우팅**: 각 토픽은 토픽 구성에 `agentId`를 설정하여 다른 에이전트로 라우팅할 수 있습니다. 이를 통해 각 토픽은 격리된 작업 공간, 메모리, 세션을 갖습니다. 예시:\n\n```json5\n{\n  channels: {\n    telegram: {\n      groups: {\n        &quot;-1001234567890&quot;: {\n          topics: {\n            &quot;1&quot;: { agentId: &quot;main&quot; },      // General topic → main agent\n            &quot;3&quot;: { agentId: &quot;zu&quot; },        // Dev topic → zu agent\n            &quot;5&quot;: { agentId: &quot;coder&quot; }      // Code review → coder agent\n          }\n        }\n      }\n    }\n  }\n}\n```\n\n그러면 각 토픽은 고유한 세션 키를 갖습니다: `agent:zu:telegram:group:-1001234567890:topic:3`\n\n**영구 ACP 토픽 바인딩**: 포럼 토픽은 최상위 typed ACP 바인딩 (`bindings[]`에 `type: &quot;acp&quot;` 및 `match.channel: &quot;telegram&quot;`, `peer.kind: &quot;group&quot;`, `-1001234567890:topic:42` 같은 topic-qualified id)을 통해 ACP harness 세션을 고정할 수 있습니다. 현재는 그룹/슈퍼그룹의 포럼 토픽으로 scope됩니다. [ACP Agents](/tools/acp-agents)를 참조하세요.\n\n**채팅에서 Thread-bound ACP spawn**: `/acp spawn &lt;agent&gt; --thread here|auto`는 현재 토픽을 새 ACP 세션에 바인딩합니다. 후속 메시지는 직접 그곳으로 라우팅됩니다. OpenClaw는 spawn 확인을 in-topic으로 고정합니다. `channels.telegram.threadBindings.spawnAcpSessions=true`가 필요합니다.\n\n템플릿 컨텍스트는 `MessageThreadId`와 `IsForum`을 노출합니다. `message_thread_id`가 있는 DM 채팅은 DM 라우팅을 유지하지만 thread-aware 세션 키를 사용합니다.\n</code></pre></details><details class="details custom-block"><summary>오디오, 비디오, 스티커</summary><h3 id="오디오-메시지" tabindex="-1">오디오 메시지 <a class="header-anchor" href="#오디오-메시지" aria-label="Permalink to &quot;오디오 메시지&quot;">​</a></h3><pre><code>Telegram은 voice note와 오디오 파일을 구분합니다.\n\n- 기본: 오디오 파일 동작\n- 에이전트 응답의 `[[audio_as_voice]]` 태그로 voice-note 전송 강제\n\n메시지 액션 예시:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;send&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  media</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com/voice.ogg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  asVoice</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>### 비디오 메시지\n\nTelegram은 비디오 파일과 video note를 구분합니다.\n\n메시지 액션 예시:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;send&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  media</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com/video.mp4&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  asVideoNote</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>Video note는 캡션을 지원하지 않으며, 제공된 메시지 텍스트는 별도로 전송됩니다.\n\n### 스티커\n\n인바운드 스티커 처리:\n\n- static WEBP: 다운로드 및 처리됨 (placeholder `&lt;media:sticker&gt;`)\n- animated TGS: 건너뜀\n- video WEBM: 건너뜀\n\n스티커 컨텍스트 필드:\n\n- `Sticker.emoji`\n- `Sticker.setName`\n- `Sticker.fileId`\n- `Sticker.fileUniqueId`\n- `Sticker.cachedDescription`\n\n스티커 캐시 파일:\n\n- `~/.openclaw/telegram/sticker-cache.json`\n\n스티커는 (가능한 경우) 한 번 설명되고 캐시되어 반복적인 비전 호출을 줄입니다.\n\n스티커 액션 활성화:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      actions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        sticker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>스티커 전송 액션:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sticker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  fileId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CAACAgIAAxkBAAI...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>캐시된 스티커 검색:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sticker-search&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  query</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cat waving&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  limit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></details><details class="details custom-block"><summary>Reaction 알림</summary><p>Telegram reaction은 <code>message_reaction</code> 업데이트로 도착합니다 (메시지 페이로드와 별개).</p><pre><code>활성화되면, OpenClaw는 다음과 같은 시스템 이벤트를 enqueue합니다:\n\n- `Telegram reaction added: 👍 by Alice (@alice) on msg 42`\n\n구성:\n\n- `channels.telegram.reactionNotifications`: `off | own | all` (기본값: `own`)\n- `channels.telegram.reactionLevel`: `off | ack | minimal | extensive` (기본값: `minimal`)\n\n참고:\n\n- `own`은 봇이 보낸 메시지에 대한 사용자 reaction만을 의미합니다 (sent-message cache를 통한 best-effort).\n- Reaction 이벤트는 여전히 Telegram 접근 제어(`dmPolicy`, `allowFrom`, `groupPolicy`, `groupAllowFrom`)를 존중하며, 권한 없는 발신자는 drop됩니다.\n- Telegram은 reaction 업데이트에 thread ID를 제공하지 않습니다.\n  - non-forum 그룹은 그룹 채팅 세션으로 라우팅됩니다\n  - forum 그룹은 정확한 원본 토픽이 아닌 그룹 general-topic 세션 (`:topic:1`)으로 라우팅됩니다\n\npolling/webhook을 위한 `allowed_updates`는 자동으로 `message_reaction`을 포함합니다.\n</code></pre></details><details class="details custom-block"><summary>Ack reactions</summary><p><code>ackReaction</code>은 OpenClaw가 인바운드 메시지를 처리하는 동안 확인(acknowledgement) 이모지를 전송합니다.</p><pre><code>해석 순서:\n\n- `channels.telegram.accounts.&lt;accountId&gt;.ackReaction`\n- `channels.telegram.ackReaction`\n- `messages.ackReaction`\n- 에이전트 identity 이모지 폴백 (`agents.list[].identity.emoji`, 없으면 &quot;👀&quot;)\n\n참고:\n\n- Telegram은 유니코드 이모지를 기대합니다 (예: &quot;👀&quot;).\n- 채널 또는 계정의 reaction을 비활성화하려면 `&quot;&quot;`를 사용하세요.\n</code></pre></details><details class="details custom-block"><summary>Telegram 이벤트 및 명령에서 Config 쓰기</summary><p>채널 config 쓰기는 기본적으로 활성화되어 있습니다 (<code>configWrites !== false</code>).</p><pre><code>Telegram 트리거 쓰기에는 다음이 포함됩니다:\n\n- `channels.telegram.groups`를 업데이트하기 위한 그룹 마이그레이션 이벤트 (`migrate_to_chat_id`)\n- `/config set`과 `/config unset` (명령 활성화 필요)\n\n비활성화:\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      configWrites</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></details><details class="details custom-block"><summary>Long polling vs webhook</summary><p>기본값은 long polling입니다. Webhook 모드의 경우 <code>channels.telegram.webhookUrl</code>과 <code>channels.telegram.webhookSecret</code>을 설정하세요. 선택적으로 <code>webhookPath</code>, <code>webhookHost</code>, <code>webhookPort</code>를 설정할 수 있습니다 (기본값 <code>/telegram-webhook</code>, <code>127.0.0.1</code>, <code>8787</code>).</p><pre><code>로컬 리스너는 `127.0.0.1:8787`에 바인딩됩니다. public ingress의 경우, 로컬 포트 앞에 리버스 프록시를 두거나 의도적으로 `webhookHost: &quot;0.0.0.0&quot;`을 설정하세요.\n</code></pre></details><details class="details custom-block"><summary>제한, 재시도, CLI 대상</summary><ul><li><p><code>channels.telegram.textChunkLimit</code> 기본값은 4000입니다.</p><ul><li><code>channels.telegram.chunkMode=&quot;newline&quot;</code>은 길이 분할 전에 단락 경계(빈 줄)를 선호합니다.</li><li><code>channels.telegram.mediaMaxMb</code> (기본 100)는 인바운드 및 아웃바운드 Telegram 미디어 크기를 제한합니다.</li><li><code>channels.telegram.timeoutSeconds</code>는 Telegram API 클라이언트 타임아웃을 override합니다 (설정되지 않으면 grammY 기본값이 적용됨).</li><li><code>channels.telegram.pollingStallThresholdMs</code>는 기본적으로 <code>120000</code>입니다. false-positive polling-stall 재시작을 위해서만 <code>30000</code>과 <code>600000</code> 사이에서 튜닝하세요.</li><li>그룹 컨텍스트 히스토리는 <code>channels.telegram.historyLimit</code> 또는 <code>messages.groupChat.historyLimit</code>(기본 50)을 사용합니다. <code>0</code>은 비활성화합니다.</li><li>답장/인용/전달 보조 컨텍스트는 현재 받은 대로 전달됩니다.</li><li>Telegram allowlist는 주로 누가 에이전트를 트리거할 수 있는지를 게이팅하며, 전체 보조 컨텍스트 redaction 경계는 아닙니다.</li><li>DM 히스토리 제어: <ul><li><code>channels.telegram.dmHistoryLimit</code></li><li><code>channels.telegram.dms[&quot;&lt;user_id&gt;&quot;].historyLimit</code></li></ul></li><li><code>channels.telegram.retry</code> 구성은 복구 가능한 아웃바운드 API 오류에 대해 Telegram 전송 헬퍼(CLI/tools/actions)에 적용됩니다.</li></ul><p>CLI 전송 대상은 숫자 채팅 ID 또는 사용자 이름이 될 수 있습니다:</p></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 123456789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hi&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @name</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hi&quot;</span></span></code></pre></div><pre><code>Telegram poll은 `openclaw message poll`을 사용하며 포럼 토픽을 지원합니다:\n</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> poll</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 123456789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --poll-question</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Ship it?&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --poll-option</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Yes&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --poll-option</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;No&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> message</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> poll</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1001234567890:topic:42</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --poll-question</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Pick a time&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --poll-option</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;10am&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --poll-option</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2pm&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --poll-duration-seconds</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 300</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --poll-public</span></span></code></pre></div><pre><code>Telegram 전용 poll 플래그:\n\n- `--poll-duration-seconds` (5-600)\n- `--poll-anonymous`\n- `--poll-public`\n- 포럼 토픽용 `--thread-id` (또는 `:topic:` 타겟 사용)\n\nTelegram 전송은 다음도 지원합니다:\n\n- `channels.telegram.capabilities.inlineButtons`가 허용할 때 인라인 키보드를 위한 `buttons` 블록이 포함된 `--presentation`\n- 봇이 해당 채팅에서 고정할 수 있을 때 고정 전송을 요청하는 `--pin` 또는 `--delivery &#39;{&quot;pin&quot;:true}&#39;`\n- 압축된 사진 또는 애니메이션 미디어 업로드 대신 아웃바운드 이미지와 GIF를 문서로 전송하는 `--force-document`\n\n액션 게이팅:\n\n- `channels.telegram.actions.sendMessage=false`는 poll을 포함하여 아웃바운드 Telegram 메시지를 비활성화합니다\n- `channels.telegram.actions.poll=false`는 일반 전송은 활성화된 상태로 Telegram poll 생성을 비활성화합니다\n</code></pre></details><details class="details custom-block"><summary>Telegram에서 exec 승인</summary><p>Telegram은 승인자 DM에서 exec 승인을 지원하며, 선택적으로 원본 채팅이나 토픽에서 프롬프트를 게시할 수 있습니다. 승인자는 숫자형 Telegram 사용자 ID여야 합니다.</p><pre><code>구성 경로:\n\n- `channels.telegram.execApprovals.enabled` (최소 한 명의 승인자가 해석 가능할 때 자동 활성화)\n- `channels.telegram.execApprovals.approvers` (`allowFrom` / `defaultTo`의 숫자형 owner ID로 폴백)\n- `channels.telegram.execApprovals.target`: `dm` (기본값) | `channel` | `both`\n- `agentFilter`, `sessionFilter`\n\n채널 전달은 채팅에 명령 텍스트를 표시합니다. 신뢰할 수 있는 그룹/토픽에서만 `channel` 또는 `both`를 활성화하세요. 프롬프트가 포럼 토픽에 도착하면, OpenClaw는 승인 프롬프트와 후속 조치를 위해 토픽을 보존합니다. Exec 승인은 기본적으로 30분 후 만료됩니다.\n\n인라인 승인 버튼은 또한 `channels.telegram.capabilities.inlineButtons`가 대상 표면(`dm`, `group`, 또는 `all`)을 허용하도록 요구합니다. `plugin:` 접두사가 붙은 승인 ID는 플러그인 승인을 통해 해석되고, 나머지는 먼저 exec 승인을 통해 해석됩니다.\n\n[Exec 승인](/tools/exec-approvals)을 참조하세요.\n</code></pre></details><h2 id="오류-응답-제어" tabindex="-1">오류 응답 제어 <a class="header-anchor" href="#오류-응답-제어" aria-label="Permalink to &quot;오류 응답 제어&quot;">​</a></h2><p>에이전트가 전달 또는 공급자 오류에 부딪히면, Telegram은 오류 텍스트로 응답하거나 이를 억제할 수 있습니다. 두 개의 config 키가 이 동작을 제어합니다:</p><table tabindex="0"><thead><tr><th>키</th><th>값</th><th>기본값</th><th>설명</th></tr></thead><tbody><tr><td><code>channels.telegram.errorPolicy</code></td><td><code>reply</code>, <code>silent</code></td><td><code>reply</code></td><td><code>reply</code>는 친절한 오류 메시지를 채팅에 전송합니다. <code>silent</code>는 오류 응답을 완전히 억제합니다.</td></tr><tr><td><code>channels.telegram.errorCooldownMs</code></td><td>number (ms)</td><td><code>60000</code></td><td>동일 채팅에 대한 오류 응답 간 최소 시간입니다. 장애 동안 오류 spam을 방지합니다.</td></tr></tbody></table><p>계정별, 그룹별, 토픽별 override가 지원됩니다 (다른 Telegram config 키와 동일한 상속).</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      errorPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;reply&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      errorCooldownMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">120000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;-1001234567890&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          errorPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;silent&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// suppress errors in this group</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><details class="details custom-block"><summary>봇이 멘션 없는 그룹 메시지에 응답하지 않음</summary><ul><li><code>requireMention=false</code>인 경우, Telegram privacy mode가 전체 가시성을 허용해야 합니다. - BotFather: <code>/setprivacy</code> -&gt; Disable - 그런 다음 그룹에서 봇을 제거 후 다시 추가 <ul><li><code>openclaw channels status</code>는 config가 멘션 없는 그룹 메시지를 기대할 때 경고합니다.</li><li><code>openclaw channels status --probe</code>는 명시적인 숫자 그룹 ID를 확인할 수 있습니다. 와일드카드 <code>&quot;*&quot;</code>는 membership-probe될 수 없습니다.</li><li>빠른 세션 테스트: <code>/activation always</code>.</li></ul></li></ul></details><details class="details custom-block"><summary>봇이 그룹 메시지를 전혀 보지 못함</summary><ul><li><code>channels.telegram.groups</code>가 존재할 때, 그룹이 나열되어 있어야 합니다 (또는 <code>&quot;*&quot;</code> 포함) <ul><li>그룹의 봇 멤버십 확인</li><li>로그 검토: skip 사유를 위한 <code>openclaw logs --follow</code></li></ul></li></ul></details><details class="details custom-block"><summary>명령이 부분적으로 또는 전혀 작동하지 않음</summary><ul><li>발신자 신원 인증 (페어링 및/또는 숫자형 <code>allowFrom</code>) <ul><li>그룹 정책이 <code>open</code>인 경우에도 명령 인증이 여전히 적용됨</li><li><code>setMyCommands failed</code>와 <code>BOT_COMMANDS_TOO_MUCH</code>는 네이티브 메뉴에 항목이 너무 많음을 의미합니다. 플러그인/스킬/커스텀 명령을 줄이거나 네이티브 메뉴를 비활성화하세요</li><li><code>setMyCommands failed</code>와 네트워크/fetch 오류는 보통 <code>api.telegram.org</code>로의 DNS/HTTPS 도달 가능성 문제를 나타냅니다</li></ul></li></ul></details><details class="details custom-block"><summary>Polling 또는 네트워크 불안정</summary><ul><li>Node 22+ + 커스텀 fetch/프록시는 AbortSignal 타입이 일치하지 않는 경우 즉시 abort 동작을 트리거할 수 있습니다. <ul><li>일부 호스트는 <code>api.telegram.org</code>를 IPv6로 먼저 해석합니다. 고장난 IPv6 egress는 간헐적 Telegram API 실패를 유발할 수 있습니다.</li><li>로그에 <code>TypeError: fetch failed</code> 또는 <code>Network request for &#39;getUpdates&#39; failed!</code>가 포함되면, OpenClaw는 이제 복구 가능한 네트워크 오류로 재시도합니다.</li><li>로그에 <code>Polling stall detected</code>가 포함되면, OpenClaw는 기본적으로 long-poll liveness 완료 없이 120초 후에 polling을 재시작하고 Telegram transport를 재구축합니다.</li><li>long-running <code>getUpdates</code> 호출이 정상이지만 호스트에서 여전히 false polling-stall 재시작을 보고할 때만 <code>channels.telegram.pollingStallThresholdMs</code>를 늘리세요. 지속적인 stall은 보통 호스트와 <code>api.telegram.org</code> 사이의 프록시, DNS, IPv6 또는 TLS egress 문제를 가리킵니다.</li><li>불안정한 직접 egress/TLS가 있는 VPS 호스트에서는, Telegram API 호출을 <code>channels.telegram.proxy</code>를 통해 라우팅하세요:</li></ul></li></ul><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    proxy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">socks5://&lt;user&gt;:&lt;password&gt;@proxy-host:1080</span></span></code></pre></div><pre><code>- Node 22+는 기본적으로 `autoSelectFamily=true` (WSL2 제외)와 `dnsResultOrder=ipv4first`를 사용합니다.\n- 호스트가 WSL2이거나 IPv4-only 동작에서 명시적으로 더 잘 작동하는 경우, family 선택을 강제하세요:\n</code></pre><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    network</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      autoSelectFamily</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><pre><code>- RFC 2544 벤치마크 범위 응답(`198.18.0.0/15`)은 Telegram 미디어 다운로드에 대해 기본적으로 이미 허용됩니다. 신뢰할 수 있는 fake-IP 또는 투명 프록시가 미디어 다운로드 중 `api.telegram.org`를 다른 private/internal/special-use 주소로 rewrite한다면, Telegram 전용 bypass를 opt-in할 수 있습니다:\n</code></pre><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    network</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      dangerouslyAllowPrivateNetwork</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><pre><code>- 동일한 opt-in은 계정별로 `channels.telegram.accounts.&lt;accountId&gt;.network.dangerouslyAllowPrivateNetwork`에서 사용 가능합니다.\n- 프록시가 Telegram 미디어 호스트를 `198.18.x.x`로 해석하는 경우, 먼저 위험한 플래그는 끄세요. Telegram 미디어는 이미 기본적으로 RFC 2544 벤치마크 범위를 허용합니다.\n\n::: warning\n</code></pre><p><code>channels.telegram.network.dangerouslyAllowPrivateNetwork</code>는 Telegram 미디어 SSRF 보호를 약화시킵니다. Clash, Mihomo, Surge fake-IP 라우팅처럼 RFC 2544 벤치마크 범위 외부에서 private 또는 special-use 응답을 합성할 때의 신뢰할 수 있는 operator-controlled 프록시 환경에서만 사용하세요. 일반 public 인터넷 Telegram 접근에서는 꺼 두세요.</p></details><pre><code>- 환경 변수 override (임시):\n  - `OPENCLAW_TELEGRAM_DISABLE_AUTO_SELECT_FAMILY=1`\n  - `OPENCLAW_TELEGRAM_ENABLE_AUTO_SELECT_FAMILY=1`\n  - `OPENCLAW_TELEGRAM_DNS_RESULT_ORDER=ipv4first`\n- DNS 응답 검증:\n</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.telegram.org</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> A</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.telegram.org</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AAAA</span></span></code></pre></div><p>:::</p><p>추가 도움말: <a href="/openclaw-docs-ko/channels/troubleshooting">채널 문제 해결</a>.</p><h2 id="구성-참조" tabindex="-1">구성 참조 <a class="header-anchor" href="#구성-참조" aria-label="Permalink to &quot;구성 참조&quot;">​</a></h2><p>기본 참조: <a href="/openclaw-docs-ko/gateway/config-channels#telegram">구성 참조 - Telegram</a>.</p><details class="details custom-block"><summary>주요 Telegram 필드</summary><ul><li>시작/인증: <code>enabled</code>, <code>botToken</code>, <code>tokenFile</code>, <code>accounts.*</code> (<code>tokenFile</code>은 일반 파일을 가리켜야 하며, 심볼릭 링크는 거부됩니다)</li><li>접근 제어: <code>dmPolicy</code>, <code>allowFrom</code>, <code>groupPolicy</code>, <code>groupAllowFrom</code>, <code>groups</code>, <code>groups.*.topics.*</code>, 최상위 <code>bindings[]</code> (<code>type: &quot;acp&quot;</code>)</li><li>exec 승인: <code>execApprovals</code>, <code>accounts.*.execApprovals</code></li><li>명령/메뉴: <code>commands.native</code>, <code>commands.nativeSkills</code>, <code>customCommands</code></li><li>threading/답장: <code>replyToMode</code></li><li>스트리밍: <code>streaming</code> (프리뷰), <code>streaming.preview.toolProgress</code>, <code>blockStreaming</code></li><li>포맷팅/전달: <code>textChunkLimit</code>, <code>chunkMode</code>, <code>linkPreview</code>, <code>responsePrefix</code></li><li>미디어/네트워크: <code>mediaMaxMb</code>, <code>timeoutSeconds</code>, <code>pollingStallThresholdMs</code>, <code>retry</code>, <code>network.autoSelectFamily</code>, <code>network.dangerouslyAllowPrivateNetwork</code>, <code>proxy</code></li><li>webhook: <code>webhookUrl</code>, <code>webhookSecret</code>, <code>webhookPath</code>, <code>webhookHost</code></li><li>액션/기능: <code>capabilities.inlineButtons</code>, <code>actions.sendMessage|editMessage|deleteMessage|reactions|sticker</code></li><li>reaction: <code>reactionNotifications</code>, <code>reactionLevel</code></li><li>오류: <code>errorPolicy</code>, <code>errorCooldownMs</code></li><li>쓰기/히스토리: <code>configWrites</code>, <code>historyLimit</code>, <code>dmHistoryLimit</code>, <code>dms.*.historyLimit</code></li></ul></details><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Multi-account 우선순위: 두 개 이상의 계정 ID가 구성된 경우, 기본 라우팅을 명시적으로 만들기 위해 <code>channels.telegram.defaultAccount</code>를 설정하거나 <code>channels.telegram.accounts.default</code>를 포함하세요. 그렇지 않으면 OpenClaw는 첫 번째 정규화된 계정 ID로 폴백하며 <code>openclaw doctor</code>가 경고합니다. 명명된 계정은 <code>channels.telegram.allowFrom</code> / <code>groupAllowFrom</code>을 상속하지만, <code>accounts.default.*</code> 값은 상속하지 않습니다.</p></div><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><blockquote><p><strong>페어링</strong> Telegram 사용자를 게이트웨이에 페어링합니다.</p></blockquote><blockquote><p><strong>그룹</strong> 그룹 및 토픽 allowlist 동작입니다.</p></blockquote><blockquote><p><strong>채널 라우팅</strong> 인바운드 메시지를 에이전트로 라우팅합니다.</p></blockquote><blockquote><p><strong>보안</strong> 위협 모델 및 hardening입니다.</p></blockquote><blockquote><p><strong>멀티 에이전트 라우팅</strong> 그룹과 토픽을 에이전트에 매핑합니다.</p></blockquote><blockquote><p><strong>문제 해결</strong> 채널 간 진단입니다.</p></blockquote>',81)])])}const E=i(l,[["render",t]]);export{c as __pageData,E as default};
